import pandas as pd
import glob
import os
import re

def compile_adaptation_results(base_dir):
    """
    Crawls the adaptation directory, parses parameters from filenames, 
    and compiles a master DataFrame of all active learning trajectories.
    """
    # The target directory based on experiment1.yaml and main.nf
    target_dir = os.path.join(base_dir, "phylogenetic_gmm", "experiments", "adapt")
    
    # We are looking for the CSV logs generated by adapt.py
    search_pattern = os.path.join(target_dir, "*_batch_log.csv")
    csv_files = glob.glob(search_pattern)
    
    if not csv_files:
        print(f"No CSV files found in {target_dir}. Please check the path.")
        return None
        
    print(f"Found {len(csv_files)} batch log files. Compiling...")
    
    all_data = []
    
    # Regex to extract parameters from the filename: 
    # e.g., adapted_model_S42_NP100000_Shf1.0_B64_H512_batch_log.csv
    file_pattern = re.compile(r"adapted_model_S(\d+)_NP(\d+)_Shf([\d\.]+)_B(\d+)_H(\d+)_batch_log\.csv")
    
    for file_path in csv_files:
        filename = os.path.basename(file_path)
        match = file_pattern.match(filename)
        
        if match:
            seed = int(match.group(1))
            n_pool = int(match.group(2))
            shift = float(match.group(3))
            batch_size = int(match.group(4))
            hidden_dim = int(match.group(5))
            
            # Read the CSV (columns: batch_number,samples_seen,train_loss,test_ce,test_f1)
            df = pd.read_csv(file_path)
            
            # Append our experimental parameters as new columns
            df['seed'] = seed
            df['n_pool'] = n_pool
            df['shift'] = shift
            df['batch_size'] = batch_size
            df['hidden_dim'] = hidden_dim
            
            all_data.append(df)
        else:
            print(f"Warning: Filename {filename} did not match expected pattern.")

    # Concatenate all dataframes into one master dataframe
    master_df = pd.concat(all_data, ignore_index=True)
    
    # Sort for logical viewing
    master_df.sort_values(by=['shift', 'n_pool', 'hidden_dim', 'batch_size', 'seed', 'batch_number'], inplace=True)
    
    return master_df

if __name__ == "__main__":
    # Point this to your metrics_dir defined in experiment1.yaml
    RESULTS_DIR = "/work/ah2lab/LiamK/plm-thesis-dynamics/results"
    
    master_df = compile_adaptation_results(RESULTS_DIR)
    
    if master_df is not None:
        output_file = os.path.join(RESULTS_DIR, "master_adaptation_results.csv")
        master_df.to_csv(output_file, index=False)
        
        print("\n--- Data Compilation Successful ---")
        print(f"Total rows: {len(master_df):,}")
        print(f"Saved compiled dataset to: {output_file}")
        print("\nData Preview:")
        print(master_df.head())
